import React, { useEffect, useState } from 'react';
import { Brand } from '../types';
import { X, ExternalLink, Youtube, ShoppingCart, PlayCircle } from 'lucide-react';

interface BrandModalProps {
  brand: Brand;
  onClose: () => void;
}

export const BrandModal: React.FC<BrandModalProps> = ({ brand, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  const getLinkIcon = (type: string) => {
    switch (type) {
      case 'video': return <Youtube className="w-4 h-4 mr-2" />;
      case 'store': return <ShoppingCart className="w-4 h-4 mr-2" />;
      case 'primary': return <PlayCircle className="w-4 h-4 mr-2" />;
      default: return <ExternalLink className="w-4 h-4 mr-2" />;
    }
  };

  return (
    <div 
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'}`}
    >
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={handleClose} />

      <div 
        className={`relative w-full max-w-4xl max-h-[90vh] overflow-y-auto glass-card rounded-2xl border-2 border-white/10 transition-transform duration-500 ${isVisible ? 'scale-100 translate-y-0' : 'scale-95 translate-y-10'}`}
        style={{ borderColor: `${brand.theme.accent}33` }}
      >
        <button 
          onClick={handleClose}
          className="absolute top-4 right-4 z-20 p-2 rounded-full glass-card hover:bg-white/10 transition-colors"
        >
          <X className="w-6 h-6" />
        </button>

        <div className="grid md:grid-cols-2">
          <div className="h-64 md:h-full relative overflow-hidden">
            <img 
              src={brand.imageUrl} 
              alt={brand.name} 
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent md:bg-gradient-to-r" />
          </div>

          <div className="p-8 md:p-12 space-y-6">
            <div>
              <span 
                className="inline-block px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest mb-4 font-futuristic"
                style={{ backgroundColor: brand.theme.accent, color: '#000' }}
              >
                {brand.category}
              </span>
              <h2 className="text-4xl font-futuristic font-black mb-4 tracking-tight leading-tight">
                {brand.name}
              </h2>
              <div className="w-20 h-1 mb-6" style={{ backgroundColor: brand.theme.accent }} />
              <p className="text-gray-300 text-lg leading-relaxed font-light">
                {brand.longDescription || brand.description}
              </p>
            </div>

            <div className="flex flex-wrap gap-4 pt-6">
              {brand.links.map((link, idx) => (
                <a
                  key={idx}
                  href={link.url}
                  className={`flex items-center px-6 py-3 rounded-lg font-bold transition-all duration-300 ${
                    link.type === 'primary' 
                      ? 'bg-red-600 hover:bg-red-700 text-white' 
                      : 'glass-card border border-white/20 hover:border-white/40'
                  }`}
                  style={link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                >
                  {getLinkIcon(link.type)}
                  {link.label}
                </a>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { CategoryType, Brand } from './types';
import { BRANDS, CATEGORY_ICONS } from './constants';
import { BrandCard } from './components/BrandCard';
import { BrandModal } from './components/BrandModal';
import { ChevronDown, Globe, Menu, Search } from 'lucide-react';

const App: React.FC = () => {
  const [activeCategory, setActiveCategory] = useState<CategoryType | 'all'>('all');
  const [selectedBrand, setSelectedBrand] = useState<Brand | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredBrands = useMemo(() => {
    return BRANDS.filter(brand => {
      const matchesCategory = activeCategory === 'all' || brand.category === activeCategory;
      const matchesSearch = brand.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            brand.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchTerm]);

  return (
    <div className="min-h-screen bg-black text-white selection:bg-red-600 selection:text-white pb-20">
      {/* Header / Navigation */}
      <header className="sticky top-0 z-40 bg-black/80 backdrop-blur-xl border-b border-white/10">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-red-600 rounded-lg flex items-center justify-center font-futuristic font-black text-xl shadow-[0_0_15px_rgba(220,38,38,0.6)]">
              H
            </div>
            <h1 className="font-futuristic text-2xl font-black tracking-tighter uppercase hidden sm:block">
              Hektic <span className="text-red-600">Hub</span>
            </h1>
          </div>

          <div className="hidden md:flex items-center gap-8">
            <button 
              onClick={() => setActiveCategory('all')}
              className={`font-futuristic text-xs uppercase tracking-widest transition-colors ${activeCategory === 'all' ? 'text-red-600' : 'text-gray-400 hover:text-white'}`}
            >
              All Access
            </button>
            {(Object.keys(CATEGORY_ICONS) as CategoryType[]).map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`font-futuristic text-xs uppercase tracking-widest transition-colors ${activeCategory === cat ? 'text-red-600' : 'text-gray-400 hover:text-white'}`}
              >
                {cat}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <div className="relative group hidden sm:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500 group-focus-within:text-red-500 transition-colors" />
              <input 
                type="text" 
                placeholder="Find a brand..." 
                className="bg-white/5 border border-white/10 rounded-full py-2 pl-10 pr-4 text-sm focus:outline-none focus:ring-1 focus:ring-red-600 w-48 lg:w-64 transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <button className="p-2 rounded-full glass-card hover:bg-white/10 transition-colors">
              <Menu className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <section className="relative h-[50vh] flex flex-col items-center justify-center text-center overflow-hidden">
        {/* Animated Background Elements */}
        <div className="absolute inset-0 z-0">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-red-600/10 rounded-full blur-[120px] animate-pulse-red" />
          <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />
        </div>

        <div className="relative z-10 max-w-4xl px-6">
          <h2 className="font-futuristic text-5xl md:text-7xl font-black mb-6 leading-none tracking-tight">
            THE <span className="text-red-600 red-glow">HEKTIC</span> ECOSYSTEM
