          {filteredBrands.length === 0 && (
            <div className="col-span-full py-20 text-center glass-card rounded-2xl">
              <p className="text-gray-500 font-futuristic text-lg">No brands found matching your criteria.</p>
              <button 
                onClick={() => {setSearchTerm(''); setActiveCategory('all');}}
                className="mt-4 text-red-500 hover:underline text-sm font-bold"
              >
                Clear all filters
              </button>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="mt-40 pt-20 pb-10 border-t border-white/10 px-6">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-12">
          <div className="space-y-6">
            <h4 className="font-futuristic text-xl font-black uppercase">Hektic <span className="text-red-600">Hub</span></h4>
            <p className="text-gray-500 text-sm leading-relaxed max-w-xs">
