          <div className="flex gap-8">
            <a href="#" className="hover:text-white transition-colors">TERMS OF SERVICE</a>
            <a href="#" className="hover:text-white transition-colors">SECURITY ENCRYPTION</a>
          </div>
        </div>
      </footer>

      {/* Brand Detail Modal */}
      {selectedBrand && (
        <BrandModal 
          brand={selectedBrand} 
          onClose={() => setSelectedBrand(null)} 
        />
      )}
