  brand: Brand;
  onClose: () => void;
}

type ModalView = 'details' | 'inquiry';

export const BrandModal: React.FC<BrandModalProps> = ({ brand, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [view, setView] = useState<ModalView>('details');
  const [selectedDate, setSelectedDate] = useState<number | null>(null);

  const isWedding = brand.id === 'premiere-weddings';

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  const getLinkIcon = (type: string) => {
    switch (type) {
      case 'video': return <Youtube className="w-4 h-4 mr-2" />;
      case 'store': return <ShoppingCart className="w-4 h-4 mr-2" />;
      case 'primary': return <PlayCircle className="w-4 h-4 mr-2" />;
      default: return <ExternalLink className="w-4 h-4 mr-2" />;
    }
  };

  const WeddingCalendar = () => {
    const days = Array.from({ length: 31 }, (_, i) => i + 1);
    return (
      <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-6 border border-rose-200 shadow-sm">
        <div className="flex items-center justify-between mb-4">
          <h4 className="font-romantic text-xl text-rose-900 italic">Select a Date</h4>
          <span className="text-sm font-medium text-rose-400">June 2025</span>
        </div>
        <div className="grid grid-cols-7 gap-2">
          {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => (
            <div key={d} className="text-center text-[10px] font-bold text-rose-300 mb-2">{d}</div>
          ))}
          {days.map(day => (
            <button
              key={day}
              onClick={() => setSelectedDate(day)}
              className={`h-10 w-full rounded-lg text-sm transition-all duration-300 flex items-center justify-center
                ${selectedDate === day 
                  ? 'bg-rose-600 text-white shadow-lg scale-110' 
                  : 'hover:bg-rose-100 text-rose-800'}`}
            >
              {day}
            </button>
          ))}
        </div>
        {selectedDate && (
          <div className="mt-6 animate-fade-in">
            <button className="w-full bg-rose-600 text-white py-3 rounded-xl font-bold font-romantic text-lg shadow-lg hover:bg-rose-700 transition-all flex items-center justify-center gap-2">
              <Check className="w-5 h-5" /> Book June {selectedDate}, 2025
            </button>
          </div>
        )}
      </div>
    );
  };

  const InquiryScreen = () => (
    <div className="animate-fade-in space-y-8">
      <button 
        onClick={() => setView('details')}
        className={`flex items-center text-sm font-bold uppercase tracking-widest ${isWedding ? 'text-rose-600' : 'text-gray-400'} mb-4`}
      >
        <ChevronLeft className="w-4 h-4 mr-1" /> Back to Brand
      </button>

      <div className="relative aspect-video rounded-3xl overflow-hidden shadow-2xl border-4 border-white">
        <div className="absolute inset-0 bg-black/20 z-10 flex items-center justify-center group cursor-pointer">
           <div className="w-20 h-20 bg-white/30 backdrop-blur-md rounded-full flex items-center justify-center group-hover:scale-110 transition-transform border border-white/40">
              <PlayCircle className="w-12 h-12 text-white" />
           </div>
        </div>
        <img 
          src="https://images.unsplash.com/photo-1511795409834-ef04bbd61622?auto=format&fit=crop&q=80&w=1200" 
          alt="Wedding Reel" 
          className="w-full h-full object-cover"
        />
        <div className="absolute bottom-6 left-6 z-20">
          <h3 className="font-romantic text-3xl text-white italic drop-shadow-md">The 2025 Wedding Reel</h3>
        </div>
      </div>

      <div className="grid md:grid-cols-2 gap-12 items-start">
        <div className="space-y-6">
          <h2 className="text-4xl font-romantic text-rose-900 leading-tight">Begin Your Story With Us</h2>
          <p className="text-rose-800/70 text-lg italic leading-relaxed">
            "We don't just record weddings; we preserve the light, the laughter, and the legacy of your love."
          </p>
          <div className="space-y-4">
             <div className="flex items-center gap-4 text-rose-700">
                <div className="w-10 h-10 rounded-full bg-rose-100 flex items-center justify-center"><Heart className="w-5 h-5" /></div>
                <span>Cinematic 4K Storytelling</span>
             </div>
             <div className="flex items-center gap-4 text-rose-700">
                <div className="w-10 h-10 rounded-full bg-rose-100 flex items-center justify-center"><CalendarIcon className="w-5 h-5" /></div>
                <span>Full-Day Event Coverage</span>
             </div>
          </div>
        </div>

        <WeddingCalendar />
      </div>
    </div>
  );

  const themeClasses = isWedding 
    ? "wedding-bg text-rose-900" 
    : "bg-black/90 text-white";

  return (
    <div 
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'}`}
    >
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={handleClose} />

      <div 
        className={`relative w-full max-w-5xl max-h-[90vh] overflow-y-auto glass-card rounded-[2.5rem] border-2 transition-transform duration-500 ${isVisible ? 'scale-100 translate-y-0' : 'scale-95 translate-y-10'} ${themeClasses}`}
        style={{ borderColor: isWedding ? '#fecaca' : `${brand.theme.accent}33` }}
      >
        <button 
          onClick={handleClose}
          className={`absolute top-6 right-6 z-20 p-2 rounded-full transition-colors ${isWedding ? 'bg-rose-100 hover:bg-rose-200 text-rose-900' : 'glass-card hover:bg-white/10 text-white'}`}
        >
          <X className="w-6 h-6" />
        </button>

        <div className="p-8 md:p-16">
          {view === 'details' ? (
            <div className="grid md:grid-cols-2 gap-12 items-center">
              <div className={`relative rounded-3xl overflow-hidden shadow-2xl ${isWedding ? 'border-8 border-white' : ''}`}>
                <img 
                  src={brand.imageUrl} 
                  alt={brand.name} 
                  className="w-full h-full object-cover"
                />
                <div className={`absolute inset-0 bg-gradient-to-t ${isWedding ? 'from-rose-200/40' : 'from-black/60'} to-transparent`} />
              </div>

              <div className="space-y-6">
                <div>
                  <span 
                    className={`inline-block px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest mb-4 font-futuristic ${isWedding ? 'bg-rose-600 text-white' : ''}`}
                    style={!isWedding ? { backgroundColor: brand.theme.accent, color: '#000' } : {}}
                  >
                    {brand.category}
                  </span>
                  <h2 className={`text-5xl mb-4 tracking-tight leading-tight ${isWedding ? 'font-romantic italic font-normal' : 'font-futuristic font-black'}`}>
                    {brand.name}
                  </h2>
                  <div className={`w-24 h-1 mb-8 ${isWedding ? 'bg-rose-300' : ''}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-lg leading-relaxed ${isWedding ? 'font-romantic text-rose-800' : 'text-gray-300 font-light'}`}>
                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className="flex flex-wrap gap-4 pt-6">
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if (isWedding && link.label === 'Inquire Now') {
                          setView('inquiry');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-8 py-4 rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-1 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-lg hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'bg-red-600 hover:bg-red-700 text-white' 
                            : 'glass-card border border-white/20 hover:border-white/40'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                    >
                      {getLinkIcon(link.type)}
                      <span className={isWedding ? 'font-romantic text-lg' : ''}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : (
            <InquiryScreen />
          )}
        </div>
      </div>
    </div>
  );
};

