interface BrandModalProps {
  brand: Brand;
  onClose: () => void;
}

type ModalView = 'details' | 'inquiry';

export const BrandModal: React.FC<BrandModalProps> = ({ brand, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [view, setView] = useState<ModalView>('details');
  const [selectedDate, setSelectedDate] = useState<number | null>(null);

  const isWedding = brand.id === 'premiere-weddings';

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  const getLinkIcon = (type: string) => {
    switch (type) {
      case 'video': return <Youtube className="w-4 h-4 mr-2" />;
      case 'store': return <ShoppingCart className="w-4 h-4 mr-2" />;
      case 'primary': return <PlayCircle className="w-4 h-4 mr-2" />;
      default: return <ExternalLink className="w-4 h-4 mr-2" />;
    }
  };

  const WeddingCalendar = () => {
    const days = Array.from({ length: 31 }, (_, i) => i + 1);
    return (
      <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-6 border border-rose-200 shadow-sm">
        <div className="flex items-center justify-between mb-4">
          <h4 className="font-romantic text-xl text-rose-900 italic">Select a Date</h4>
          <span className="text-sm font-medium text-rose-400">June 2025</span>
        </div>
        <div className="grid grid-cols-7 gap-2">
          {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => (
            <div key={d} className="text-center text-[10px] font-bold text-rose-300 mb-2">{d}</div>
          ))}
          {days.map(day => (
            <button
              key={day}
              onClick={() => setSelectedDate(day)}
              className={`h-10 w-full rounded-lg text-sm transition-all duration-300 flex items-center justify-center
                ${selectedDate === day 
                  ? 'bg-rose-600 text-white shadow-lg scale-110' 
                  : 'hover:bg-rose-100 text-rose-800'}`}
            >
              {day}
            </button>
          ))}
        </div>
        {selectedDate && (
          <div className="mt-6 animate-fade-in">
            <button className="w-full bg-rose-600 text-white py-3 rounded-xl font-bold font-romantic text-lg shadow-lg hover:bg-rose-700 transition-all flex items-center justify-center gap-2">
              <Check className="w-5 h-5" /> Book June {selectedDate}, 2025
            </button>
          </div>
        )}
      </div>
    );
  };

  const InquiryScreen = () => (
    <div className="animate-fade-in space-y-8">
      <button 
        onClick={() => setView('details')}
        className={`flex items-center text-sm font-bold uppercase tracking-widest ${isWedding ? 'text-rose-600' : 'text-gray-400'} mb-4`}
      >
        <ChevronLeft className="w-4 h-4 mr-1" /> Back to Brand
      </button>

