                      ? 'bg-rose-600 text-white shadow-md' 
                      : 'bg-white border border-rose-100 text-rose-600 hover:border-rose-300'}`}
                >
                  {time}
                </button>
              ))}
            </div>
          </div>
        )}

        {selectedTime && (
          <div className="animate-fade-in space-y-4 pt-4 border-t border-rose-100">
