                >
                  {option}
                </button>
              ))}
            </div>
          </div>
        )}

        {selectedInterest && (
          <div className="mt-6 animate-fade-in">
            <button 
              onClick={() => setView('success')}
              className="w-full bg-rose-600 text-white py-4 rounded-2xl font-bold font-romantic text-lg shadow-xl hover:bg-rose-700 hover:shadow-2xl transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1 active:scale-95"
            >
              <Check className="w-6 h-6" /> Confirm Booking
            </button>
          </div>
        )}
      </div>
    );
  };

