              <div className="lg:w-3/5 relative aspect-video lg:aspect-auto">
                <img src={hotApp.imageUrl} alt={hotApp.name} className="w-full h-full object-cover" />
                <div className="absolute top-8 left-8 bg-red-600 text-white px-4 py-2 rounded-full font-futuristic text-xs font-black uppercase tracking-widest flex items-center gap-2 shadow-lg">
                  <Flame className="w-4 h-4" /> App Highlight
                </div>
              </div>
              <div className="lg:w-2/5 p-10 lg:p-14 flex flex-col justify-center space-y-6">
                <span className="text-red-500 font-futuristic text-sm font-bold uppercase tracking-[0.2em]">{hotApp.category}</span>
                <h3 className="font-futuristic text-4xl font-black uppercase tracking-tight">{hotApp.name}</h3>
                <p className="text-gray-400 text-lg font-light leading-relaxed">{hotApp.description}</p>
                <button className="flex items-center gap-3 text-white font-bold hover:gap-5 transition-all w-fit">
                  Learn more <ArrowRight className="w-5 h-5 text-red-600" />
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Library Section */}
        <div className="space-y-8">
          <div className="flex items-center gap-4">
            <Layout className="w-6 h-6 text-red-600" />
            <h3 className="font-futuristic text-2xl font-black uppercase tracking-widest">App Library</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {otherApps.map(app => (
              <div key={app.id} className="group relative bg-white/5 rounded-3xl overflow-hidden border border-white/10 hover:border-red-600/50 transition-all duration-500 flex flex-col h-full">
                <div className="aspect-[4/3] overflow-hidden">
                  <img src={app.imageUrl} alt={app.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
