                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const VideoTrailerScreen = () => (
    <div className="relative aspect-video lg:aspect-auto h-full min-h-[400px] rounded-[2.5rem] overflow-hidden shadow-2xl border-4 border-white/10 group cursor-pointer">
      <div className="absolute inset-0 bg-black/40 z-10 flex items-center justify-center">
         <div className="w-20 h-20 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center group-hover:scale-110 transition-transform border border-white/30">
            <PlayCircle className="w-12 h-12 text-white" />
         </div>
      </div>
      <img 
        src={brand.imageUrl} 
        alt={`${brand.name} Trailer`} 
        className="w-full h-full object-cover"
      />
      <div className="absolute bottom-10 left-10 z-20">
        <h3 className="font-futuristic text-3xl text-white font-black drop-shadow-lg uppercase tracking-[0.2em]">Official Trailer</h3>
      </div>
    </div>
  );

  const themeClasses = isWedding 
    ? "wedding-bg text-rose-900" 
    : "bg-black/90 text-white";

  return (
    <div 
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'}`}
    >
      <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={handleClose} />

      <div 
        className={`relative w-full max-w-6xl max-h-[95vh] overflow-y-auto glass-card rounded-[3rem] border-2 transition-transform duration-500 shadow-2xl ${isVisible ? 'scale-100 translate-y-0' : 'scale-95 translate-y-10'} ${themeClasses} no-scrollbar`}
        style={{ borderColor: isWedding ? '#fecaca' : `${brand.theme.accent}33` }}
      >
        <button 
          onClick={handleClose}
          className={`absolute top-8 right-8 z-20 p-3 rounded-full transition-all duration-300 hover:rotate-90 ${isWedding ? 'bg-rose-100 hover:bg-rose-200 text-rose-900' : 'glass-card hover:bg-white/10 text-white'}`}
        >
          <X className="w-6 h-6" />
        </button>

        <div className="p-8 md:p-16 lg:p-20">
          {view === 'details' ? (
            <div className={isWedding ? 'max-w-4xl mx-auto text-center' : 'grid lg:grid-cols-2 gap-16 items-center'}>
              {/* Left Column Logic */}
              {isBandWars ? (
                <VideoTrailerScreen />
              ) : !isWedding && (
                <div className="relative rounded-[2.5rem] overflow-hidden shadow-2xl transform transition-transform duration-700 hover:scale-[1.02]">
                  <img 
                    src={brand.imageUrl} 
                    alt={brand.name} 
                    className="w-full aspect-[4/5] lg:aspect-auto h-full object-cover"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                </div>
              )}

              {/* Right Column Logic */}
              <div className={isWedding ? 'space-y-10' : 'space-y-8'}>
                <div>
                  <span 
                    className={`inline-block px-5 py-2 rounded-full text-xs font-bold uppercase tracking-[0.2em] mb-6 font-futuristic ${isWedding ? 'bg-rose-600 text-white shadow-lg' : ''}`}
                    style={!isWedding ? { backgroundColor: brand.theme.accent, color: '#000' } : {}}
                  >
                    {brand.category}
                  </span>
                  <h2 className={`text-6xl mb-6 tracking-tight leading-tight ${isWedding ? 'font-romantic italic font-normal' : 'font-futuristic font-black'}`}>
                    {brand.name}
                  </h2>
                  <div className={`w-32 h-1.5 mb-10 rounded-full mx-auto md:mx-0 ${isWedding ? 'bg-rose-300 mx-auto' : ''}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-xl leading-relaxed ${isWedding ? 'font-romantic text-rose-800 italic max-w-3xl mx-auto' : 'text-gray-300 font-light'}`}>
                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className={`flex flex-wrap gap-6 pt-6 ${isWedding ? 'justify-center' : ''}`}>
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if (isWedding && link.label === 'Inquire Now') {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-10 py-5 rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-2 hover:shadow-2xl active:scale-95 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-xl hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'bg-red-600 hover:bg-red-700 text-white shadow-[0_10px_20px_rgba(220,38,38,0.3)]' 
                            : 'glass-card border-2 border-white/20 hover:border-white/60'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                    >
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-xl' : ''}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <PortfolioScreen />
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

