import React, { useEffect, useState, useMemo } from 'react';
import { Brand, AppProject } from '../types';
import { 
  X, 
  ExternalLink, 
  Youtube, 
  ShoppingCart, 
  PlayCircle, 
  ChevronLeft, 
  Calendar as CalendarIcon, 
  Heart, 
  Check, 
  UserCheck, 
  ClipboardCheck, 
  Clock, 
  Sparkles,
  Smartphone,
  Flame,
  Layout,
  ArrowRight
} from 'lucide-react';

interface BrandModalProps {
  brand: Brand;
  onClose: () => void;
}

type ModalView = 'details' | 'inquiry' | 'success' | 'portfolio';

export const BrandModal: React.FC<BrandModalProps> = ({ brand, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [view, setView] = useState<ModalView>('details');
  const [selectedDate, setSelectedDate] = useState<number | null>(null);
  const [selectedTime, setSelectedTime] = useState<string | null>(null);
  const [selectedInterest, setSelectedInterest] = useState<string | null>(null);

  const isWedding = brand.id === 'premiere-weddings';
  const isBandWars = brand.id === 'band-wars';
  const isPocketopia = brand.id === 'pocketopia';

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  const getLinkIcon = (label: string, type: string) => {
    if (label.toLowerCase().includes('get the app')) return <Smartphone className="w-4 h-4 mr-2" />;

    switch (type) {
      case 'video': return <Youtube className="w-4 h-4 mr-2" />;
      case 'store': return <ShoppingCart className="w-4 h-4 mr-2" />;
      case 'primary': return <PlayCircle className="w-4 h-4 mr-2" />;
      default: return <ExternalLink className="w-4 h-4 mr-2" />;
    }
  };

  const timeSlots = [
    "09:00 AM", "10:30 AM", "12:00 PM", "01:30 PM", "03:00 PM", "04:30 PM", "06:00 PM"
  ];

  const interestOptions = [
    "Cinematic 4K Storytelling",
    "Full-Day Event Coverage",
    "Professional Wedding Officiant",
    "Full & Day-of Wedding Coordination"
  ];

  const WeddingCalendar = () => {
    const days = Array.from({ length: 31 }, (_, i) => i + 1);

    return (
      <div className="bg-white/60 backdrop-blur-sm rounded-3xl p-6 border border-rose-200 shadow-xl space-y-6">
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h4 className="font-romantic text-xl text-rose-900 italic flex items-center gap-2">
              <CalendarIcon className="w-5 h-5" /> Select a Date
            </h4>
            <span className="text-sm font-medium text-rose-400">June 2025</span>
          </div>
          <div className="grid grid-cols-7 gap-2">
            {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => (
              <div key={d} className="text-center text-[10px] font-bold text-rose-300 mb-2">{d}</div>
            ))}
            {days.map(day => (
              <button
                key={day}
                onClick={() => setSelectedDate(day)}
                className={`h-9 w-full rounded-lg text-sm transition-all duration-300 flex items-center justify-center
                  ${selectedDate === day 
                    ? 'bg-rose-600 text-white shadow-lg scale-110' 
                    : 'hover:bg-rose-100 text-rose-800'}`}
              >
                {day}
              </button>
            ))}
          </div>
        </div>

        {selectedDate && (
          <div className="animate-fade-in space-y-4 pt-4 border-t border-rose-100">
            <h4 className="font-romantic text-xl text-rose-900 italic flex items-center gap-2">
              <Clock className="w-5 h-5" /> Select a Time
            </h4>
            <div className="flex flex-wrap gap-2">
              {timeSlots.map(time => (
                <button
                  key={time}
                  onClick={() => setSelectedTime(time)}
                  className={`px-3 py-1.5 rounded-full text-xs transition-all duration-300
                    ${selectedTime === time 
                      ? 'bg-rose-600 text-white shadow-md' 
                      : 'bg-white border border-rose-100 text-rose-600 hover:border-rose-300'}`}
                >
                  {time}
                </button>
              ))}
            </div>
          </div>
        )}

        {selectedTime && (
          <div className="animate-fade-in space-y-4 pt-4 border-t border-rose-100">
            <h4 className="font-romantic text-xl text-rose-900 italic flex items-center gap-2">
              <Sparkles className="w-5 h-5" /> What are you interested in?
            </h4>
            <div className="max-h-32 overflow-y-auto pr-2 space-y-2 no-scrollbar">
              {interestOptions.map(option => (
                <button
                  key={option}
                  onClick={() => setSelectedInterest(option)}
                  className={`w-full text-left px-4 py-2.5 rounded-xl text-xs transition-all duration-300 border
                    ${selectedInterest === option 
                      ? 'bg-rose-50 border-rose-500 text-rose-900 font-bold' 
                      : 'bg-white border-rose-100 text-rose-600 hover:border-rose-200'}`}
