import React, { useEffect, useState, useMemo } from 'react';
import { Brand, AppProject } from '../types';
import { 
  X, 
  ExternalLink, 
  Youtube, 
  ShoppingCart, 
  PlayCircle, 
  ChevronLeft, 
  Calendar as CalendarIcon, 
  Heart, 
  Check, 
  UserCheck, 
  ClipboardCheck, 
  Clock, 
  Sparkles,
  Smartphone,
  Flame,
  Layout,
  ArrowRight
} from 'lucide-react';

interface BrandModalProps {
  brand: Brand;
  onClose: () => void;
}

type ModalView = 'details' | 'inquiry' | 'success' | 'portfolio';

