                    className="w-full aspect-[4/5] lg:aspect-auto h-full object-cover"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                </div>
              )}

              {/* Text Content Logic */}
              <div className={isWedding ? 'space-y-2 sm:space-y-10' : 'space-y-6 sm:space-y-8'}>
                <div>
                  <span 
                    className={`inline-block px-3 py-1 sm:px-5 sm:py-2 rounded-full text-[8px] sm:text-xs font-bold uppercase tracking-[0.2em] mb-1 sm:mb-6 font-futuristic ${isWedding ? 'bg-rose-600 text-white shadow-lg' : ''}`}
