                  >
                    {brand.category}
                  </span>
                  <h2 className={`text-xl sm:text-6xl mb-1 sm:mb-6 tracking-tight leading-tight ${isWedding ? 'font-romantic italic font-normal' : 'font-futuristic font-black'}`}>
                    {brand.name}
                  </h2>
                  <div className={`w-12 sm:w-32 h-0.5 sm:h-1.5 mb-2 sm:mb-10 rounded-full ${isWedding ? 'bg-rose-300 mx-auto' : 'mx-auto md:mx-0'}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-xs sm:text-xl leading-relaxed ${isWedding ? 'font-romantic text-rose-800 italic max-w-3xl mx-auto' : 'text-gray-300 font-light'}`}>
                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className={`flex flex-wrap gap-2 sm:gap-6 pt-1 sm:pt-6 ${isWedding ? 'justify-center' : 'justify-center lg:justify-start'}`}>
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if (isWedding && link.label === 'Inquire Now') {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-4 py-2.5 sm:px-10 sm:py-5 rounded-lg sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-2 hover:shadow-2xl active:scale-95 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-xl hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'bg-red-600 hover:bg-red-700 text-white shadow-[0_10px_20px_rgba(220,38,38,0.3)]' 
                            : 'glass-card border-2 border-white/20 hover:border-white/60'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                    >
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-sm sm:text-xl' : 'text-[10px] sm:text-base'}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <PortfolioScreen />
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { Brand, AppProject } from '../types';
import { 
  X, 
  ExternalLink, 
  Youtube, 
  ShoppingCart, 
  PlayCircle, 
  ChevronLeft, 
  Calendar as CalendarIcon, 
  Heart, 
  Check, 
  UserCheck, 
  ClipboardCheck, 
  Clock, 
  Sparkles,
  Smartphone,
  Flame,
  Layout,
  ArrowRight
} from 'lucide-react';

interface BrandModalProps {
  brand: Brand;
  onClose: () => void;
}

type ModalView = 'details' | 'inquiry' | 'success' | 'portfolio';

export const BrandModal: React.FC<BrandModalProps> = ({ brand, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [view, setView] = useState<ModalView>('details');
  const [selectedDate, setSelectedDate] = useState<number | null>(null);
  const [selectedTime, setSelectedTime] = useState<string | null>(null);
  const [selectedInterest, setSelectedInterest] = useState<string | null>(null);

  const isWedding = brand.id === 'premiere-weddings';
  const isBandWars = brand.id === 'band-wars';
  const isPocketopia = brand.id === 'pocketopia';

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  const getLinkIcon = (label: string, type: string) => {
    if (label.toLowerCase().includes('get the app')) return <Smartphone className="w-4 h-4 mr-2" />;

    switch (type) {
      case 'video': return <Youtube className="w-4 h-4 mr-2" />;
      case 'store': return <ShoppingCart className="w-4 h-4 mr-2" />;
      case 'primary': return <PlayCircle className="w-4 h-4 mr-2" />;
      default: return <ExternalLink className="w-4 h-4 mr-2" />;
    }
