                <div className={`flex flex-wrap gap-2 sm:gap-6 pt-1 sm:pt-6 ${isWedding ? 'justify-center' : 'justify-center lg:justify-start'}`}>
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if (isWedding && link.label === 'Inquire Now') {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-4 py-2 sm:px-10 sm:py-5 rounded-lg sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-2 hover:shadow-2xl active:scale-95 ${
