                    className={`inline-block px-3 py-1 sm:px-5 sm:py-2 rounded-full text-[8px] sm:text-xs font-bold uppercase tracking-[0.15em] mb-1 sm:mb-6 font-futuristic ${isWedding ? 'bg-rose-600 text-white shadow-lg' : ''}`}
