                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className={`flex flex-wrap gap-2 sm:gap-6 pt-1 sm:pt-6 ${isWedding ? 'justify-center' : 'justify-center lg:justify-start'}`}>
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if (isWedding && link.label === 'Inquire Now') {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-5 py-3 sm:px-10 sm:py-5 rounded-lg sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-2 hover:shadow-2xl active:scale-95 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-xl hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'bg-red-600 hover:bg-red-700 text-white shadow-[0_10px_20px_rgba(220,38,38,0.3)]' 
                            : 'glass-card border-2 border-white/20 hover:border-white/60'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                    >
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-sm sm:text-xl' : 'text-[10px] sm:text-base'}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <PortfolioScreen />
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
