                </div>
              ) : !isWedding && (
                <div className="relative rounded-[1.5rem] sm:rounded-[2.5rem] overflow-hidden shadow-2xl transform transition-transform duration-700 hover:scale-[1.02]">
                  <img 
                    src={brand.imageUrl} 
                    alt={brand.name} 
                    className="w-full aspect-[4/5] lg:aspect-auto h-full object-cover"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                </div>
              )}

              {/* Text Content Logic */}
              <div className={isWedding ? 'space-y-2.5 sm:space-y-10' : 'space-y-6 sm:space-y-8'}>
                <div className="flex flex-col items-center">
                  <span 
                    className={`inline-block px-2.5 py-1 sm:px-5 sm:py-2 rounded-full text-[8px] sm:text-xs font-bold uppercase tracking-[0.15em] mb-1 sm:mb-6 font-futuristic ${isWedding ? 'bg-rose-600 text-white shadow-lg' : ''}`}
                    style={!isWedding ? { backgroundColor: brand.theme.accent, color: '#000' } : {}}
                  >
                    {brand.category}
                  </span>
                  <h2 className={`mb-1 sm:mb-6 tracking-tight leading-tight ${isWedding ? 'font-romantic italic font-normal text-xl sm:text-6xl' : 'font-futuristic font-black text-xl sm:text-6xl'}`}>
                    {brand.name}
                  </h2>
                  <div className={`h-0.5 sm:h-1.5 mb-2 sm:mb-10 rounded-full ${isWedding ? 'bg-rose-300 w-12 sm:w-32' : 'w-12 sm:w-32 mx-auto md:mx-0'}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-[12px] sm:text-xl leading-relaxed ${isWedding ? 'font-romantic text-rose-800 italic max-w-xl mx-auto line-clamp-3 sm:line-clamp-none' : 'text-gray-300 font-light'}`}>
                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className={`flex flex-wrap gap-2 sm:gap-6 pt-1 sm:pt-6 ${isWedding ? 'justify-center' : 'justify-center lg:justify-start'}`}>
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if (isWedding && link.label === 'Inquire Now') {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-6 py-3 sm:px-10 sm:py-5 rounded-lg sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-1 hover:shadow-2xl active:scale-95 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-lg hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'bg-red-600 hover:bg-red-700 text-white shadow-[0_10px_20px_rgba(220,38,38,0.3)]' 
                            : 'glass-card border-2 border-white/20 hover:border-white/60'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                    >
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-base sm:text-xl' : 'text-[10px] sm:text-base'}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <PortfolioScreen />
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
