                  <Flame className="w-3 h-3 sm:w-4 sm:h-4" /> App Highlight
                </div>
              </div>
              <div className="lg:w-2/5 p-6 sm:p-10 lg:p-14 flex flex-col justify-center space-y-4 sm:space-y-6">
