                <h3 className="font-futuristic text-2xl sm:text-4xl font-black uppercase tracking-tight">{hotApp.name}</h3>
                <p className="text-gray-400 text-sm sm:text-lg font-light leading-relaxed">{hotApp.description}</p>
                <button className="flex items-center gap-3 text-white text-sm sm:text-base font-bold hover:gap-5 transition-all w-fit">
                  Learn more <ArrowRight className="w-4 h-4 sm:w-5 sm:h-5 text-red-600" />
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Library Section */}
        <div className="space-y-6 sm:space-y-8">
          <div className="flex items-center gap-4">
            <Layout className="w-5 h-5 sm:w-6 sm:h-6 text-red-600" />
            <h3 className="font-futuristic text-xl sm:text-2xl font-black uppercase tracking-widest">App Library</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
            {otherApps.map(app => (
              <div key={app.id} className="group relative bg-white/5 rounded-3xl overflow-hidden border border-white/10 hover:border-red-600/50 transition-all duration-500 flex flex-col h-full">
                <div className="aspect-[4/3] overflow-hidden">
                  <img src={app.imageUrl} alt={app.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                </div>
                <div className="p-4 sm:p-6 space-y-3 sm:space-y-4 flex-1 flex flex-col">
                  <span className="text-[8px] sm:text-[10px] font-futuristic font-bold text-gray-500 uppercase tracking-widest">{app.category}</span>
                  <h4 className="font-futuristic text-lg sm:text-xl font-bold uppercase">{app.name}</h4>
                  <p className="text-gray-400 text-xs sm:text-sm font-light line-clamp-2">{app.description}</p>
                  <div className="pt-2 sm:pt-4 mt-auto">
                    <button className="text-[10px] sm:text-xs font-bold uppercase tracking-widest text-red-500 hover:text-white transition-colors">View Details</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const VideoTrailerScreen = ({ title }: { title?: string }) => (
    <div className={`relative aspect-video lg:aspect-auto w-full h-full rounded-[0.75rem] sm:rounded-[2.5rem] overflow-hidden shadow-2xl border sm:border-4 border-white/10 group cursor-pointer ${isWedding ? 'min-h-[200px] sm:min-h-[400px]' : 'min-h-[110px] sm:min-h-[400px]'}`}>
      <div className="absolute inset-0 bg-black/40 z-10 flex items-center justify-center">
         <div className={`bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center group-hover:scale-110 transition-transform border border-white/30 ${isWedding ? 'w-10 h-10 sm:w-20 sm:h-20' : 'w-7 h-7 sm:w-20 sm:h-20'}`}>
            <PlayCircle className={`${isWedding ? 'w-6 h-6 sm:w-12 sm:h-12' : 'w-4 h-4 sm:w-12 sm:h-12'} text-white`} />
         </div>
      </div>
      <img 
        src={isWedding ? "https://images.unsplash.com/photo-1511795409834-ef04bbd61622?auto=format&fit=crop&q=80&w=1200" : brand.imageUrl} 
        alt={`${brand.name} Trailer`} 
        className="w-full h-full object-cover"
      />
      <div className="absolute bottom-2 left-3 sm:bottom-10 sm:left-10 z-20">
        <h3 className={`text-white font-black drop-shadow-lg uppercase ${isWedding ? 'font-romantic text-[12px] sm:text-4xl italic tracking-tight' : 'font-futuristic text-lg sm:text-3xl tracking-[0.05em] sm:tracking-[0.2em]'}`}>
          {title || "Official Trailer"}
        </h3>
      </div>
    </div>
  );

  const themeClasses = isWedding 
    ? "wedding-bg text-rose-900" 
    : "bg-black/90 text-white";

  return (
    <div 
      className={`fixed inset-0 z-50 flex items-center justify-center transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'} ${isWedding ? 'p-0 sm:p-4' : 'p-2 sm:p-4'}`}
    >
      <div className="absolute inset-0 bg-black/95 backdrop-blur-md" onClick={handleClose} />

      <div 
        className={`relative w-full transition-transform duration-500 shadow-2xl ${isVisible ? 'scale-100 translate-y-0' : 'scale-95 translate-y-10'} ${themeClasses} no-scrollbar
          ${isWedding 
            ? 'h-full sm:h-auto sm:max-h-[95vh] sm:max-w-6xl sm:rounded-[3rem] sm:border overflow-y-auto' 
            : 'max-w-6xl max-h-[95vh] rounded-[1.25rem] sm:rounded-[3rem] border overflow-y-auto'
          }`}
        style={{ borderColor: isWedding ? '#fecaca' : `${brand.theme.accent}33` }}
      >
        <button 
          onClick={handleClose}
          className={`absolute z-30 p-2 sm:p-3 rounded-full transition-all duration-300 hover:rotate-90 
            ${isWedding ? 'top-4 right-4 bg-rose-100 hover:bg-rose-200 text-rose-900 shadow-md' : 'top-2 right-2 sm:top-8 sm:right-8 glass-card hover:bg-white/10 text-white'}`}
        >
          <X className="w-5 h-5 sm:w-6 sm:h-6" />
        </button>

        <div className={`${(isWedding || isPocketopia) && view === 'details' ? 'p-0 pt-10 sm:p-12 lg:p-20' : 'p-2 sm:p-12 lg:p-20'}`}>
          {view === 'details' ? (
            <div className={isWedding ? 'max-w-4xl mx-auto text-center flex flex-col items-center justify-center space-y-0 sm:space-y-12' : 'grid lg:grid-cols-2 gap-8 sm:gap-16 items-center'}>
              {/* Top Media Logic */}
              {(isBandWars || isWedding) ? (
                <div className={isWedding ? 'w-full mb-6 sm:mb-8' : 'w-full'}>
                  <VideoTrailerScreen title={isWedding ? "The 2025 Wedding Reel" : undefined} />
                </div>
              ) : !isWedding && (
                <div className="relative rounded-[1.5rem] sm:rounded-[2.5rem] overflow-hidden shadow-2xl transform transition-transform duration-700 hover:scale-[1.02]">
                  <img 
                    src={brand.imageUrl} 
                    alt={brand.name} 
                    className="w-full aspect-[4/5] lg:aspect-auto h-full object-cover"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                </div>
              )}

              {/* Text Content Logic */}
              <div className={`${isWedding ? 'space-y-6 sm:space-y-10 pb-16 sm:pb-0 px-4' : 'space-y-6 sm:space-y-8'}`}>
                <div className="flex flex-col items-center">
                  <span 
                    className={`inline-block px-3 py-1 sm:px-5 sm:py-2 rounded-full text-[10px] sm:text-xs font-bold uppercase tracking-[0.15em] mb-2 sm:mb-6 font-futuristic ${isWedding ? 'bg-rose-600 text-white shadow-lg' : ''}`}
                    style={!isWedding ? { backgroundColor: brand.theme.accent, color: '#000' } : {}}
                  >
                    {brand.category}
                  </span>
                  <h2 className={`mb-2 sm:mb-6 tracking-tight leading-tight ${isWedding ? 'font-romantic italic font-normal text-2xl sm:text-6xl' : 'font-futuristic font-black text-xl sm:text-6xl'}`}>
                    {brand.name}
                  </h2>
                  <div className={`h-0.5 sm:h-1.5 mb-3 sm:mb-10 rounded-full ${isWedding ? 'bg-rose-300 w-20 sm:w-32' : 'w-12 sm:w-32 mx-auto md:mx-0'}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-[14px] sm:text-xl leading-relaxed ${isWedding ? 'font-romantic text-rose-800 italic max-w-xl mx-auto px-2' : 'text-gray-300 font-light'}`}>
                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className={`flex flex-wrap gap-3 sm:gap-6 pt-2 sm:pt-6 ${isWedding ? 'justify-center' : 'justify-center lg:justify-start'}`}>
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if ((isWedding || isPocketopia) && link.label.includes('Inquire')) {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-6 py-4 sm:px-10 sm:py-5 rounded-xl sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-1 hover:shadow-2xl active:scale-95 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-lg hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'bg-red-600 hover:bg-red-700 text-white shadow-[0_10px_20px_rgba(220,38,38,0.3)]' 
                            : 'glass-card border-2 border-white/20 hover:border-white/60'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent } : {}}
                    >
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-lg sm:text-xl' : 'text-[11px] sm:text-base'}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <PortfolioScreen />
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { Brand, AppProject } from '../types';
import { 
  X, 
  ExternalLink, 
  Youtube, 
  ShoppingCart, 
  PlayCircle, 
  ChevronLeft, 
  Calendar as CalendarIcon, 
  Heart, 
  Check, 
  UserCheck, 
  ClipboardCheck, 
  Clock, 
  Sparkles,
  Smartphone,
  Flame,
  Layout,
  ArrowRight,
  Monitor,
  Zap
} from 'lucide-react';

interface BrandModalProps {
  brand: Brand;
  onClose: () => void;
}

type ModalView = 'details' | 'inquiry' | 'success' | 'portfolio';

export const BrandModal: React.FC<BrandModalProps> = ({ brand, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [view, setView] = useState<ModalView>('details');
  const [selectedDate, setSelectedDate] = useState<number | null>(null);
  const [selectedTime, setSelectedTime] = useState<string | null>(null);
  const [selectedInterest, setSelectedInterest] = useState<string | null>(null);
  const [selectedAppType, setSelectedAppType] = useState<string | null>(null);

  const isWedding = brand.id === 'premiere-weddings';
  const isBandWars = brand.id === 'band-wars';
  const isPocketopia = brand.id === 'pocketopia';

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  const getLinkIcon = (label: string, type: string) => {
    if (label.toLowerCase().includes('get the app')) return <Smartphone className="w-4 h-4 mr-2" />;

    switch (type) {
      case 'video': return <Youtube className="w-4 h-4 mr-2" />;
      case 'store': return <ShoppingCart className="w-4 h-4 mr-2" />;
      case 'primary': return <PlayCircle className="w-4 h-4 mr-2" />;
      default: return <ExternalLink className="w-4 h-4 mr-2" />;
    }
  };

  const timeSlots = [
    "09:00 AM", "10:30 AM", "12:00 PM", "01:30 PM", "03:00 PM", "04:30 PM", "06:00 PM"
  ];

  const interestOptions = isWedding ? [
    "Cinematic 4K Storytelling",
    "Full-Day Event Coverage",
    "Professional Wedding Officiant",
    "Full & Day-of Wedding Coordination"
  ] : [
    "Mobile iOS/Android App",
    "Web Application",
    "E-commerce Platform",
    "AI scheduling/email services",
    "Custom Enterprise Software",
    "Other"
  ];

  const CalendarComponent = () => {
    const days = Array.from({ length: 31 }, (_, i) => i + 1);
    const accentColor = isWedding ? 'rose' : 'red';
    const accentHex = isWedding ? '#e11d48' : (isPocketopia ? '#ffffff' : '#dc2626');

    return (
      <div className={`bg-white/60 backdrop-blur-sm rounded-3xl p-4 sm:p-6 border border-${accentColor}-200 shadow-xl space-y-4 sm:space-y-6`}>
        <div className="space-y-3 sm:space-y-4">
          <div className="flex items-center justify-between">
            <h4 className={`${isWedding ? 'font-romantic italic text-rose-900' : 'font-futuristic font-bold text-gray-900'} text-lg sm:text-xl flex items-center gap-2`}>
              <CalendarIcon className="w-4 h-4 sm:w-5 sm:h-5" /> Select a Date
            </h4>
            <span className={`text-xs font-medium ${isWedding ? 'text-rose-400' : 'text-gray-400'}`}>June 2025</span>
          </div>
          <div className="grid grid-cols-7 gap-1 sm:gap-2">
            {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => (
              <div key={d} className={`text-center text-[10px] font-bold ${isWedding ? 'text-rose-300' : 'text-gray-300'} mb-1`}>{d}</div>
            ))}
            {days.map(day => (
              <button
                key={day}
                onClick={() => setSelectedDate(day)}
                className={`h-8 sm:h-9 w-full rounded-lg text-xs sm:text-sm transition-all duration-300 flex items-center justify-center
                  ${selectedDate === day 
                    ? `text-white shadow-lg scale-110` 
                    : `hover:bg-${accentColor}-100 text-${accentColor}-800`}`}
                style={selectedDate === day ? { backgroundColor: isPocketopia ? '#000000' : accentHex } : {}}
              >
                {day}
              </button>
            ))}
          </div>
        </div>

        {selectedDate && (
          <div className={`animate-fade-in space-y-3 sm:space-y-4 pt-3 sm:pt-4 border-t border-${accentColor}-100`}>
            <h4 className={`${isWedding ? 'font-romantic italic text-rose-900' : 'font-futuristic font-bold text-gray-900'} text-lg sm:text-xl flex items-center gap-2`}>
              <Clock className="w-4 h-4 sm:w-5 sm:h-5" /> Select a Time
            </h4>
            <div className="flex flex-wrap gap-1.5 sm:gap-2">
              {timeSlots.map(time => (
                <button
                  key={time}
                  onClick={() => setSelectedTime(time)}
                  className={`px-2.5 py-1 sm:px-3 sm:py-1.5 rounded-full text-[10px] sm:text-xs transition-all duration-300
                    ${selectedTime === time 
                      ? `text-white shadow-md` 
                      : `bg-white border border-${accentColor}-100 text-${accentColor}-600 hover:border-${accentColor}-300`}`}
                  style={selectedTime === time ? { backgroundColor: isPocketopia ? '#000000' : accentHex } : {}}
                >
                  {time}
                </button>
              ))}
            </div>
          </div>
        )}

        {(isWedding ? selectedTime : (selectedTime && selectedAppType)) && (
          <div className="mt-4 sm:mt-6 animate-fade-in">
            <button 
              onClick={() => setView('success')}
              className={`w-full ${isWedding ? 'bg-rose-600 font-romantic text-lg sm:text-lg' : 'bg-red-600 font-futuristic text-sm sm:text-base'} text-white py-3 sm:py-4 rounded-2xl font-bold shadow-xl hover:opacity-90 transition-all flex items-center justify-center gap-2 transform hover:-translate-y-1 active:scale-95`}
              style={{ backgroundColor: isPocketopia ? '#000000' : accentHex }}
            >
              <Check className="w-5 h-5 sm:w-6 sm:h-6" /> Confirm Booking
            </button>
          </div>
        )}
      </div>
    );
  };

  const SuccessScreen = () => (
    <div className="flex flex-col items-center justify-center py-10 sm:py-20 text-center space-y-6 sm:space-y-8 animate-fade-in h-full">
      <div className={`w-16 h-16 sm:w-24 sm:h-24 ${isWedding ? 'bg-rose-100' : 'bg-red-100'} rounded-full flex items-center justify-center animate-bounce`}>
        {isWedding ? <Heart className="w-8 h-8 sm:w-12 sm:h-12 text-rose-600 fill-rose-600" /> : <Check className="w-8 h-8 sm:w-12 sm:h-12 text-red-600" />}
      </div>
      <div className="space-y-3 sm:space-y-4">
        <h2 className={`text-3xl sm:text-5xl ${isWedding ? 'font-romantic' : 'font-futuristic font-black uppercase'} ${isWedding ? 'text-rose-900' : 'text-white'} leading-tight px-4`}>
          {isWedding ? 'Booking Submitted!' : 'INQUIRY SENT!'}
        </h2>
        <p className={`${isWedding ? 'text-rose-700/70 italic' : 'text-gray-400 font-light'} text-base sm:text-xl max-w-xs sm:max-w-md mx-auto px-4`}>
          {isWedding 
            ? "We are honored to be considered for your journey. A consultant will reach out within 24 hours."
            : "The Pocketopia engineering team is reviewing your project. Expect a response shortly."}
        </p>
      </div>
      <div className={`${isWedding ? 'bg-white/40 border-rose-200 text-rose-900 font-romantic italic' : 'glass-card border-white/10 text-white font-futuristic'} p-4 sm:p-6 rounded-3xl border text-base sm:text-lg shadow-inner mx-4`}>
        Scheduled for June {selectedDate}, 2025 at {selectedTime}
        <div className={`text-[10px] sm:text-sm mt-2 font-sans not-italic ${isWedding ? 'text-rose-400' : 'text-red-500'} font-bold uppercase tracking-widest`}>
          {isPocketopia ? selectedAppType : selectedInterest}
        </div>
      </div>
      <button 
        onClick={handleClose}
        className={`px-8 py-3 sm:px-10 sm:py-4 ${isWedding ? 'bg-rose-600' : 'bg-red-600'} text-white rounded-2xl font-bold transition-all ${isWedding ? 'font-romantic text-base sm:text-lg' : 'font-futuristic text-sm sm:text-base'}`}
      >
        Return to Hub
      </button>
    </div>
  );

  const InquiryScreen = () => {
    return (
      <div className="animate-fade-in space-y-6 sm:space-y-8 px-4 sm:px-0 py-4 sm:py-0">
        <button 
          onClick={() => setView('details')}
          className={`flex items-center text-[10px] sm:text-sm font-bold uppercase tracking-widest ${isWedding ? 'text-rose-600' : 'text-gray-400'} mb-2`}
        >
          <ChevronLeft className="w-3 h-3 sm:w-4 sm:h-4 mr-1" /> Back to Brand
        </button>

        <div className="grid lg:grid-cols-2 gap-8 sm:gap-12 items-start pt-2 sm:pt-4">
          <div className="space-y-6 sm:space-y-8 py-2 sm:py-4">
            <h2 className={`text-3xl sm:text-5xl ${isWedding ? 'font-romantic text-rose-900' : 'font-futuristic font-black uppercase text-white'} leading-tight`}>
              {isWedding ? 'Begin Your Story With Us' : 'Build Your Digital Future'}
            </h2>
            <p className={`${isWedding ? 'text-rose-800/70 italic' : 'text-gray-400 font-light'} text-lg sm:text-xl leading-relaxed`}>
              {isWedding 
                ? '"We don\'t just record weddings; we preserve the light, the laughter, and the legacy of your love."'
                : 'What kind of app do you want to create? Let\'s architect your vision and book an initial consultation.'}
            </p>

            <div className="grid grid-cols-2 gap-3 sm:gap-6">
               {isWedding ? (
                 <>
                   <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-rose-700 p-3 sm:p-4 bg-rose-50/50 rounded-2xl border border-rose-100 text-center sm:text-left">
                      <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-rose-100 flex items-center justify-center flex-shrink-0"><Heart className="w-4 h-4 sm:w-5 sm:h-5" /></div>
                      <span className="text-[10px] sm:text-sm font-medium">Cinematic 4K Storytelling</span>
                   </div>
                   <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-rose-700 p-3 sm:p-4 bg-rose-50/50 rounded-2xl border border-rose-100 text-center sm:text-left">
                      <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-rose-100 flex items-center justify-center flex-shrink-0"><CalendarIcon className="w-4 h-4 sm:w-5 sm:h-5" /></div>
                      <span className="text-[10px] sm:text-sm font-medium">Full-Day Coverage</span>
                   </div>
                 </>
               ) : (
                 <>
                   <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-gray-400 p-3 sm:p-4 glass-card rounded-2xl border border-white/10 text-center sm:text-left">
                      <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-red-600/20 flex items-center justify-center flex-shrink-0 text-red-500"><Monitor className="w-4 h-4 sm:w-5 sm:h-5" /></div>
                      <span className="text-[10px] sm:text-sm font-medium">Full-Stack Scalability</span>
                   </div>
                   <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-gray-400 p-3 sm:p-4 glass-card rounded-2xl border border-white/10 text-center sm:text-left">
                      <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-red-600/20 flex items-center justify-center flex-shrink-0 text-red-500"><Zap className="w-4 h-4 sm:w-5 sm:h-5" /></div>
                      <span className="text-[10px] sm:text-sm font-medium">Rapid Deployment</span>
                   </div>
                 </>
               )}
            </div>

            {isPocketopia && (
              <div className="space-y-4 pt-4">
                <h4 className="font-futuristic text-xs uppercase tracking-widest text-red-500">Select Project Type</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {interestOptions.map(option => (
                    <button
                      key={option}
                      onClick={() => setSelectedAppType(option)}
                      className={`text-left px-4 py-3 rounded-xl text-xs transition-all border flex items-center justify-between ${
                        selectedAppType === option 
                          ? 'border-red-600 bg-red-600/10 text-white' 
                          : 'border-white/10 hover:border-white/30 text-gray-400'
                      }`}
                    >
                      {option}
                      {selectedAppType === option && <Check className="w-3 h-3" />}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

          <CalendarComponent />
        </div>
      </div>
    );
  };

  const PortfolioScreen = () => {
    const hotApp = useMemo(() => brand.appPortfolio?.find(a => a.isHot), [brand]);
