                  </h2>
                  <div className={`h-0.5 sm:h-1.5 mb-3 sm:mb-10 rounded-full ${isWedding ? 'bg-rose-300 w-20 sm:w-32' : 'w-12 sm:w-32 mx-auto'}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-[14px] sm:text-xl leading-relaxed ${isWedding ? 'font-romantic text-rose-800 italic max-w-xl mx-auto px-2' : 'text-gray-300 font-light'}`}>
                    {brand.longDescription || brand.description}
                  </p>
                </div>

                <div className="flex flex-wrap gap-3 sm:gap-6 pt-2 sm:pt-6 justify-center">
                  {brand.links.map((link, idx) => (
                    <button
                      key={idx}
                      onClick={() => {
                        if ((isWedding || isPocketopia || isTwizted) && (link.label.includes('Inquire') || link.label.includes('Book'))) {
                          setView('inquiry');
                        } else if (isPocketopia && link.label === 'View Portfolio') {
                          setView('portfolio');
                        } else if (link.url !== '#') {
                          window.open(link.url, '_blank');
                        }
                      }}
                      className={`flex items-center px-6 py-4 sm:px-10 sm:py-5 rounded-xl sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-1 hover:shadow-2xl active:scale-95 ${
                        isWedding 
                          ? 'bg-rose-600 text-white shadow-lg hover:bg-rose-700' 
                          : link.type === 'primary' 
                            ? 'shadow-[0_10px_20px_rgba(255,255,255,0.1)]' 
                            : 'glass-card border-2 border-white/20 hover:border-white/60 text-white'
                      }`}
                      style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent, color: isLightAccent ? '#000' : '#fff' } : {}}
                    >
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-lg sm:text-xl' : 'text-[11px] sm:text-base'}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <PortfolioScreen />
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

