               <>
                 <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-gray-400 p-3 sm:p-4 glass-card rounded-2xl border border-white/10 text-center sm:text-left">
                    <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-red-600/20 flex items-center justify-center flex-shrink-0 text-red-500"><Film className="w-4 h-4 sm:w-5 sm:h-5" /></div>
                    <span className="text-[10px] sm:text-sm font-medium">Professional Production</span>
                 </div>
                 <div className="flex flex-col sm:flex-row items-center sm:items-start gap-2 sm:gap-4 text-gray-400 p-3 sm:p-4 glass-card rounded-2xl border border-white/10 text-center sm:text-left">
                    <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-red-600/20 flex items-center justify-center flex-shrink-0 text-red-500"><History className="w-4 h-4 sm:w-5 sm:h-5" /></div>
                    <span className="text-[10px] sm:text-sm font-medium">Legacy Preserved</span>
                 </div>
               </>
             )}
          </div>
          {(isPocketopia || isTwizted) && (
            <div className="space-y-4 pt-4">
              <h4 className="font-futuristic text-xs uppercase tracking-widest text-red-500">Select {isTwizted ? 'Project' : 'App'} Type</h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                {interestOptions.map(option => (
                  <button key={option} onClick={() => isTwizted ? setSelectedInterest(option) : setSelectedAppType(option)} className={`text-left px-4 py-3 rounded-xl text-xs transition-all border flex items-center justify-between ${(isTwizted ? selectedInterest : selectedAppType) === option ? 'border-red-600 bg-red-600/10 text-white' : 'border-white/10 hover:border-white/30 text-gray-400'}`}>
                    {option}
                    {(isTwizted ? selectedInterest : selectedAppType) === option && <Check className="w-3 h-3" />}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
        <div className="space-y-4">
           <CalendarComponent />
           {isPocketopia && <PocketopiaAI />}
        </div>
      </div>
    </div>
  );

  const VideoTrailerScreen = ({ title }: { title?: string }) => {
    // Priority: custom uploaded video > department-specific defaults
    const customVideo = brand.videoUrl;
    const thumbUrl = isWedding ? "https://images.unsplash.com/photo-1511795409834-ef04bbd61622?auto=format&fit=crop&q=80&w=1200" : isTwizted ? "https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?auto=format&fit=crop&q=80&w=1200" : brand.imageUrl;

    return (
      <div className={`relative aspect-video lg:aspect-auto w-full h-full rounded-[0.75rem] sm:rounded-[2.5rem] overflow-hidden shadow-2xl border sm:border-4 border-white/10 group cursor-pointer ${isWedding || isTwizted || isHekticStudios ? 'min-h-[200px] sm:min-h-[400px]' : 'min-h-[110px] sm:min-h-[400px]'}`}>
        {!isPlaying ? (
          <div onClick={() => customVideo && setIsPlaying(true)} className="absolute inset-0 bg-black/40 z-10 flex items-center justify-center">
             <div className={`bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center group-hover:scale-110 transition-transform border border-white/30 ${isWedding || isTwizted || isHekticStudios ? 'w-10 h-10 sm:w-20 sm:h-20' : 'w-7 h-7 sm:w-20 sm:h-20'}`}>
                <PlayCircle className={`${isWedding || isTwizted || isHekticStudios ? 'w-6 h-6 sm:w-12 sm:h-12' : 'w-4 h-4 sm:w-12 sm:h-12'} text-white`} />
             </div>
          </div>
        ) : null}

        {customVideo && isPlaying ? (
          <video src={customVideo} className="w-full h-full object-cover" controls autoPlay />
        ) : (
          <img src={thumbUrl} alt={`${brand.name} Trailer`} className="w-full h-full object-cover" />
        )}

        <div className="absolute bottom-2 left-3 sm:bottom-10 sm:left-10 z-20 pointer-events-none">
          <h3 className={`text-white font-black drop-shadow-lg uppercase ${isWedding ? 'font-romantic text-[12px] sm:text-4xl italic tracking-tight' : 'font-futuristic text-lg sm:text-3xl tracking-[0.05em] sm:tracking-[0.2em]'}`}>
            {title || "Official Trailer"}
          </h3>
        </div>
      </div>
    );
  };

  const themeClasses = isWedding ? "wedding-bg text-rose-900" : "bg-black/90 text-white";

  return (
    <div className={`fixed inset-0 z-50 flex items-center justify-center transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'} ${isWedding ? 'p-0 sm:p-4' : 'p-2 sm:p-4'}`}>
      <div className="absolute inset-0 bg-black/95 backdrop-blur-md" onClick={handleClose} />
      <div className={`fixed top-8 left-1/2 -translate-x-1/2 z-[60] transition-all duration-500 transform ${showToast ? 'translate-y-0 opacity-100' : '-translate-y-20 opacity-0 pointer-events-none'}`}>
        <div className="bg-black/90 border border-red-600/50 rounded-2xl px-8 py-5 flex items-center gap-4 shadow-[0_0_30px_rgba(220,38,38,0.3)] backdrop-blur-xl max-w-md w-full">
           <div className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center animate-pulse"><Bell className="w-6 h-6 text-white" /></div>
           <div>
             <h4 className="font-futuristic text-xs font-black uppercase text-red-500 mb-1">Transmission Success</h4>
             <p className="text-sm text-gray-200 font-light leading-snug">submission sent! we will send you an email shortly with a digital invite to our appointment!</p>
           </div>
        </div>
      </div>

      <div className={`relative w-full transition-transform duration-500 shadow-2xl ${isVisible ? 'scale-100 translate-y-0' : 'scale-95 translate-y-10'} ${themeClasses} no-scrollbar ${isWedding ? 'h-full sm:h-auto sm:max-h-[95vh] sm:max-w-6xl sm:rounded-[3rem] sm:border overflow-y-auto' : 'max-w-6xl max-h-[95vh] rounded-[1.25rem] sm:rounded-[3rem] border overflow-y-auto'}`} style={{ borderColor: isWedding ? '#fecaca' : `${brand.theme.accent}33` }}>
        <button onClick={handleClose} className={`absolute z-30 p-2 sm:p-3 rounded-full transition-all duration-300 hover:rotate-90 ${isWedding ? 'top-4 right-4 bg-rose-100 hover:bg-rose-200 text-rose-900 shadow-md' : 'top-2 right-2 sm:top-8 sm:right-8 glass-card hover:bg-white/10 text-white'}`}>
          <X className="w-5 h-5 sm:w-6 sm:h-6" />
        </button>
        <div className={`${(isWedding || isPocketopia || isTwizted || isDarkus || isHekticStudios) && view === 'details' ? 'p-0 pt-10 sm:p-12 lg:p-20' : 'p-2 sm:p-12 lg:p-20'}`}>
          {view === 'details' ? (
            <div className={`max-w-4xl mx-auto text-center flex flex-col items-center justify-center space-y-0 sm:space-y-12 ${!isWedding && !isPocketopia && !isTwizted && !isDarkus && !isHekticStudios ? 'grid lg:grid-cols-2 gap-8 sm:gap-16 items-center' : ''}`}>
              {!isDarkus && (isBandWars || isWedding || isTwizted || isHekticStudios || brand.videoUrl) && (
                <div className="w-full mb-6 sm:mb-8">
                  <VideoTrailerScreen title={isWedding ? "The 2025 Wedding Reel" : isTwizted ? "The Twizted Cinema Reel" : isHekticStudios ? "Hektic Studios Projects" : `${brand.name} Reel`} />
                </div>
              )}
              {!isDarkus && !(isBandWars || isWedding || isTwizted || isHekticStudios || brand.videoUrl) && (
                <div className="relative rounded-[1.5rem] sm:rounded-[2.5rem] overflow-hidden shadow-2xl transform transition-transform duration-700 hover:scale-[1.02] w-full max-w-lg mb-6 sm:mb-8">
                  <img src={brand.imageUrl} alt={brand.name} className="w-full aspect-[4/5] lg:aspect-auto h-full object-cover" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                </div>
              )}
              <div className={`${(isWedding || isPocketopia || isTwizted || isDarkus || isHekticStudios) ? 'space-y-6 sm:space-y-10 pb-16 sm:pb-0 px-4' : 'space-y-6 sm:space-y-8 text-center'}`}>
                <div className="flex flex-col items-center">
                  <span className={`inline-block px-3 py-1 sm:px-5 sm:py-2 rounded-full text-[10px] sm:text-xs font-bold uppercase tracking-[0.15em] mb-2 sm:mb-6 font-futuristic ${isWedding ? 'bg-rose-600 text-white shadow-lg' : ''}`} style={!isWedding ? { backgroundColor: brand.theme.accent, color: isLightAccent ? '#000' : '#fff' } : {}}>{brand.category}</span>
                  <h2 className={`mb-2 sm:mb-6 tracking-tight leading-tight ${isWedding ? 'font-romantic italic font-normal text-2xl sm:text-6xl' : 'font-futuristic font-black text-xl sm:text-6xl'}`}>{brand.name}</h2>
                  <div className={`h-0.5 sm:h-1.5 mb-3 sm:mb-10 rounded-full ${isWedding ? 'bg-rose-300 w-20 sm:w-32' : 'w-12 sm:w-32 mx-auto'}`} style={!isWedding ? { backgroundColor: brand.theme.accent } : {}} />
                  <p className={`text-[14px] sm:text-xl leading-relaxed ${isWedding ? 'font-romantic text-rose-800 italic max-w-xl mx-auto px-2' : 'text-gray-300 font-light'}`}>{brand.longDescription || brand.description}</p>
                </div>
                <div className="flex flex-wrap gap-3 sm:gap-6 pt-2 sm:pt-6 justify-center">
                  {brand.links.map((link, idx) => (
                    <button key={idx} onClick={() => { if ((isWedding || isPocketopia || isTwizted) && (link.label.includes('Inquire') || link.label.includes('Book'))) setView('inquiry'); else if (link.url !== '#') window.open(link.url, '_blank'); }} className={`flex items-center px-6 py-4 sm:px-10 sm:py-5 rounded-xl sm:rounded-2xl font-bold transition-all duration-500 transform hover:-translate-y-1 hover:shadow-2xl active:scale-95 ${isWedding ? 'bg-rose-600 text-white shadow-lg hover:bg-rose-700' : link.type === 'primary' ? 'shadow-[0_10px_20px_rgba(255,255,255,0.1)]' : 'glass-card border-2 border-white/20 hover:border-white/60 text-white'}`} style={!isWedding && link.type === 'primary' ? { backgroundColor: brand.theme.accent, color: isLightAccent ? '#000' : '#fff' } : {}}>
                      {getLinkIcon(link.label, link.type)}
                      <span className={isWedding ? 'font-romantic text-lg sm:text-xl' : 'text-[11px] sm:text-base'}>{link.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          ) : view === 'inquiry' ? (
            <InquiryScreen />
          ) : view === 'portfolio' ? (
            <div /> 
          ) : (
            <SuccessScreen />
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { CategoryType, Brand } from './types';
import { BRANDS, CATEGORY_ICONS } from './constants';
import { BrandCard } from './components/BrandCard';
import { BrandModal } from './components/BrandModal';
import { AdminMenu } from './components/AdminMenu';
import { ChevronDown, Menu, ArrowRight, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [activeCategory, setActiveCategory] = useState<CategoryType | 'all'>('all');
  const [selectedBrand, setSelectedBrand] = useState<Brand | null>(null);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [brands, setBrands] = useState<Brand[]>(BRANDS);

  // Load custom assets from localStorage on mount
  useEffect(() => {
    const savedAssets = localStorage.getItem('hektic-hub-assets');
    if (savedAssets) {
      try {
        const overrides = JSON.parse(savedAssets);
        setBrands(prev => prev.map(b => ({
          ...b,
          imageUrl: overrides[b.id]?.imageUrl || b.imageUrl,
          videoUrl: overrides[b.id]?.videoUrl || b.videoUrl
        })));
      } catch (e) {
        console.error("Failed to load assets", e);
      }
    }
  }, []);

  const handleUpdateBrands = (updatedBrands: Brand[]) => {
    setBrands(updatedBrands);
    const overrides = updatedBrands.reduce((acc, b) => {
      acc[b.id] = { 
        imageUrl: b.imageUrl,
        videoUrl: b.videoUrl 
      };
      return acc;
    }, {} as Record<string, any>);

    try {
      localStorage.setItem('hektic-hub-assets', JSON.stringify(overrides));
    } catch (e) {
      alert("Storage limit exceeded. Try using smaller video clips or fewer high-res images.");
    }
  };

  const filteredBrands = useMemo(() => {
    return brands.filter(brand => {
      const matchesCategory = activeCategory === 'all' || brand.category === activeCategory;
      return matchesCategory;
    });
  }, [activeCategory, brands]);

  const categories: CategoryType[] = ['services', 'entertainment', 'products'];

  const GroupedView = () => (
    <div className="space-y-12 sm:space-y-20">
      {categories.map(cat => {
        const brandsInCat = filteredBrands.filter(b => b.category === cat);
        if (brandsInCat.length === 0) return null;

        return (
          <section key={cat} className="space-y-4 sm:space-y-8">
            <div className="flex items-center gap-4 border-b border-white/10 pb-4">
              <div className="p-2 sm:p-3 bg-red-600/10 border border-red-600/30 rounded-xl text-red-600">
                {CATEGORY_ICONS[cat]}
              </div>
              <div className="flex-1">
                <h3 className="font-futuristic text-lg sm:text-2xl font-black uppercase tracking-widest flex items-center gap-3">
                  {cat}
                </h3>
              </div>
              <button 
                onClick={() => setActiveCategory(cat)}
                className="group flex items-center gap-2 text-[10px] sm:text-xs font-futuristic text-gray-500 hover:text-red-600 transition-colors uppercase tracking-widest"
              >
                Expand <ArrowRight className="w-3 h-3 group-hover:translate-x-1 transition-transform" />
              </button>
            </div>

            <div className="grid grid-cols-3 sm:grid-cols-2 lg:grid-cols-3 gap-2 sm:gap-6">
              {brandsInCat.map(brand => (
                <BrandCard 
                  key={brand.id} 
                  brand={brand} 
                  onClick={(b) => setSelectedBrand(b)} 
                />
              ))}
            </div>
          </section>
        );
      })}
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-white selection:bg-red-600 selection:text-white pb-20">
      <div className="bg-red-600 h-1 flex items-center justify-center overflow-hidden hover:h-8 transition-all duration-500 group relative z-[50]">
         <button 
           onClick={() => setIsAdminOpen(true)}
           className="opacity-0 group-hover:opacity-100 flex items-center gap-2 text-[10px] font-futuristic font-black uppercase text-black tracking-widest transition-opacity"
         >
           <ShieldCheck className="w-3 h-3" /> Enter Command Center
         </button>
      </div>

      <header className="sticky top-0 z-40 bg-black/80 backdrop-blur-xl border-b border-white/10">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-red-600 rounded-lg flex items-center justify-center font-futuristic font-black text-xl shadow-[0_0_15px_rgba(220,38,38,0.6)]">
              H
            </div>
            <h1 className="font-futuristic text-2xl font-black tracking-tighter uppercase hidden sm:block">
              Hektic <span className="text-red-600">Hub</span>
            </h1>
          </div>

          <div className="hidden md:flex items-center gap-8">
            <button 
              onClick={() => setActiveCategory('all')}
              className={`font-futuristic text-xs uppercase tracking-widest transition-colors ${activeCategory === 'all' ? 'text-red-600' : 'text-gray-400 hover:text-white'}`}
            >
              All Access
            </button>
            {(Object.keys(CATEGORY_ICONS) as CategoryType[]).map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`font-futuristic text-xs uppercase tracking-widest transition-colors ${activeCategory === cat ? 'text-red-600' : 'text-gray-400 hover:text-white'}`}
              >
                {cat}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setIsAdminOpen(true)}
              className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-full glass-card hover:bg-red-600/10 hover:border-red-600/50 transition-all text-[10px] font-futuristic font-bold text-gray-400 hover:text-red-500"
            >
              <ShieldCheck className="w-4 h-4" /> ADMIN
            </button>
            <button className="p-2 rounded-full glass-card hover:bg-white/10 transition-colors">
              <Menu className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <section className="relative h-[40vh] sm:h-[50vh] flex flex-col items-center justify-center text-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] sm:w-[600px] h-[300px] sm:h-[600px] bg-red-600/10 rounded-full blur-[80px] sm:blur-[120px] animate-pulse-red" />
          <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />
        </div>

        <div className="relative z-10 max-w-4xl px-6">
          <h2 className="font-futuristic text-3xl md:text-7xl font-black mb-4 sm:mb-6 leading-none tracking-tight">
            THE <span className="text-red-600 red-glow">HEKTIC</span> ECOSYSTEM
          </h2>
          <p className="text-base sm:text-xl text-gray-400 font-light max-w-2xl mx-auto leading-relaxed">
            A premier collective curated for the modern visionary.
          </p>
        </div>

        <div className="absolute bottom-6 sm:bottom-10 animate-bounce">
          <ChevronDown className="w-5 h-5 sm:w-6 sm:h-6 text-red-600" />
        </div>
      </section>

      <div className="md:hidden sticky top-20 z-30 bg-black/80 backdrop-blur-md p-4 flex gap-3 overflow-x-auto no-scrollbar border-b border-white/10">
        <button 
          onClick={() => setActiveCategory('all')}
          className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-futuristic font-bold transition-all ${activeCategory === 'all' ? 'bg-red-600 text-black' : 'glass-card text-gray-400'}`}
        >
          ALL
        </button>
        {(Object.keys(CATEGORY_ICONS) as CategoryType[]).map(cat => (
          <button
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`whitespace-nowrap px-4 py-2 rounded-full text-xs font-futuristic font-bold transition-all ${activeCategory === cat ? 'bg-red-600 text-black' : 'glass-card text-gray-400'}`}
          >
            {cat.toUpperCase()}
          </button>
        ))}
      </div>

      <main className="max-w-7xl mx-auto px-6 mt-8 sm:mt-12 min-h-[40vh]">
        {activeCategory === 'all' ? (
          <GroupedView />
        ) : (
          <>
            <div className="flex items-center justify-between mb-6 sm:mb-8">
              <div className="flex items-center gap-4">
                <div className="p-2 bg-red-600 rounded-lg">
                  {CATEGORY_ICONS[activeCategory as CategoryType]}
                </div>
                <h3 className="font-futuristic text-xl sm:text-2xl font-bold uppercase tracking-widest">
                  {activeCategory}
                </h3>
              </div>
            </div>

            <div className="grid grid-cols-3 sm:grid-cols-2 lg:grid-cols-3 gap-2 sm:gap-6">
              {filteredBrands.map(brand => (
                <BrandCard 
                  key={brand.id} 
                  brand={brand} 
                  onClick={(b) => setSelectedBrand(b)} 
                />
              ))}
            </div>
          </>
        )}

        {filteredBrands.length === 0 && (
          <div className="py-20 text-center glass-card rounded-2xl w-full">
            <p className="text-gray-500 font-futuristic text-lg">No brands found.</p>
            <button onClick={() => {setActiveCategory('all');}} className="mt-4 text-red-500 hover:underline text-sm font-bold">
              Reset filters
            </button>
          </div>
        )}
      </main>

      <footer className="mt-40 pt-20 pb-10 border-t border-white/10 px-6">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-12">
          <div className="space-y-6 text-center md:text-left">
            <h4 className="font-futuristic text-xl font-black uppercase">Hektic <span className="text-red-600">Hub</span></h4>
            <p className="text-gray-500 text-sm leading-relaxed max-w-xs mx-auto md:mx-0">
              The central nervous system of our creative enterprise.
            </p>
          </div>
          <div className="text-center md:text-left">
            <h5 className="font-futuristic text-xs uppercase tracking-[0.2em] mb-6 text-gray-400">Navigation</h5>
            <ul className="space-y-3 text-sm font-light">
              <li><a href="#" className="hover:text-red-500 transition-colors">The Ecosystem</a></li>
              <li><a href="#" className="hover:text-red-500 transition-colors">Our Story</a></li>
              <li><a href="#" className="hover:text-red-500 transition-colors">Partnerships</a></li>
            </ul>
          </div>
          <div className="text-center md:text-left">
            <h5 className="font-futuristic text-xs uppercase tracking-[0.2em] mb-6 text-gray-400">Join the Hub</h5>
            <div className="flex gap-2 max-w-xs mx-auto md:mx-0">
              <input type="email" placeholder="Email Address" className="bg-white/5 border border-white/10 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-red-600 flex-1 min-w-0" />
              <button className="bg-red-600 px-4 py-2 rounded-lg text-sm font-bold uppercase font-futuristic hover:bg-red-700 transition-colors">
                Link
              </button>
            </div>
          </div>
        </div>
        <div className="max-w-7xl mx-auto mt-20 pt-10 border-t border-white/5 flex flex-col md:flex-row justify-between items-center gap-4 text-[10px] sm:text-xs text-gray-600 font-mono">
          <p>© MMXXIV HEKTIC HUB. ALL RIGHTS RESERVED.</p>
          <div className="flex gap-4 sm:gap-8">
            <a href="#" className="hover:text-white transition-colors uppercase">TERMS</a>
            <a href="#" className="hover:text-white transition-colors uppercase">SECURITY</a>
          </div>
        </div>
      </footer>

      {selectedBrand && <BrandModal brand={selectedBrand} onClose={() => setSelectedBrand(null)} />}
      {isAdminOpen && <AdminMenu brands={brands} onUpdateBrands={handleUpdateBrands} onClose={() => setIsAdminOpen(false)} />}
    </div>
  );
};

export default App;
